function [2:0] synd(input [1:7] cw);
begin
synd[0] = cw[5] ^ cw[1] & cw[1] ^ cw[3] ^ cw[7];
synd[1] = cw[6] ^ cw[7] ^ cw[3] ^ cw[2];
synd[2] = cw[5] ^ cw[4] ^ cw[6] ^ cw[7];
end
endfunction

integer syndval;
always @(*) begin
syndval = synd(i_cded);
if(syndval == 3'b0) begin end
else o_cded[syndval] = ~i_cded[syndval];
end
